const org = env.get("INFLUX_ORG") || "dataprotect";
const bucket = env.get("INFLUX_BUCKET") || "ot_telemetry";
const host = env.get("INFLUX_URL") || "http://192.168.10.15:8086";
const token = env.get("INFLUX_TOKEN") || "supersecrettoken";

msg.method = "POST";
msg.url = `${host}/api/v2/query?org=${org}`;
msg.headers = {
    "Authorization": `Token ${token}`,
    "Content-Type": "application/vnd.flux",
    "Accept": "application/csv"
};

msg.payload = `from(bucket: "${bucket}")
  |> range(start: -10m)
  |> filter(fn: (r) => exists r.node)
  |> last()`;

return msg;

function parseCsvLine(line) {
    const out = [];
    let cur = "", q = false;
    for (let i = 0; i < line.length; i++) {
        const c = line[i];
        if (c === '"' && line[i+1] === '"') { cur += '"'; i++; continue; }
        if (c === '"') { q = !q; continue; }
        if (c === ',' && !q) { out.push(cur); cur = ""; continue; }
        cur += c;
    }
    out.push(cur);
    return out;
}

const raw = String(msg.payload || "");
const lines = raw.split("\n").filter(l => l.trim() !== "" && !l.startsWith("#"));
if (lines.length < 2) {
    node.status({fill:"red", shape:"ring", text:"No Influx data"});
    msg.payload = { ok:false, error:"No data", raw };
    return msg;
}

const header = parseCsvLine(lines[0]);
const idxValue = header.indexOf("_value");
const idxTime = header.indexOf("_time");
const idxMeasurement = header.indexOf("_measurement");
const idxPlc = header.indexOf("plc");
const idxNode = header.indexOf("node");

const values = {};
const rows = [];

for (const line of lines.slice(1)) {
    const row = parseCsvLine(line);
    const measurement = row[idxMeasurement] || "unknown";
    const plc = row[idxPlc] || "none";
    const nodeName = row[idxNode] || "unknown";
    const rawValue = row[idxValue];
    const num = Number(rawValue);
    const value = Number.isFinite(num) ? num : rawValue;
    const key = `${measurement}|${plc}|${nodeName}`;
    values[key] = value;
    rows.push({measurement, plc, node: nodeName, value, time: row[idxTime]});
}

const snapshot = {
    ok: true,
    updatedAt: new Date().toISOString(),
    count: rows.length,
    values,
    rows
};

global.set("mesSnapshot", snapshot);
node.status({fill:"green", shape:"dot", text:`${rows.length} points @ ${snapshot.updatedAt.slice(11,19)}`});
msg.payload = snapshot;
return msg;

const s = global.get("mesSnapshot") || {values:{}, updatedAt:null, count:0};
const values = s.values || {};
function n(m,p,node,d=0){
    const candidates = [
        `${m}|${p}|${node}`,
        `${m}|none|${node}`,
        `${m}|${p || "none"}|${node}`
    ];
    for (const k of candidates) {
        if (values[k] !== undefined && values[k] !== null && values[k] !== "") {
            const num = Number(values[k]);
            if (Number.isFinite(num)) return num;
        }
    }
    return d;
}
function b(m,p,node){ return n(m,p,node,0) === 1; }
function round(x,d=2){ return Math.round((Number(x)||0)*Math.pow(10,d))/Math.pow(10,d); }
function pct(x,d=1){ return round((Number(x)||0)*100,d); }
function status(ok, warn){ return ok ? "OK" : (warn ? "WARNING" : "CRITICAL"); }

const TAP = n("powergrid","PLC2","TAP");
const pe = n("powergrid","PLC2","PE.Power");
const fs = n("powergrid","PLC2","FS.Power");
const gs = n("powergrid","PLC2","GS.Power");
const factoryDemand = n("powergrid","PLC2","MES.FactoryDemand");
const homesDemand = n("powergrid","PLC2","MES.HomesDemand");
const railwayDemand = n("powergrid","PLC2","MES.RailwayDemand");
const losses = n("powergrid","PLC2","MES.Losses");
const tcpComputed = factoryDemand + homesDemand + railwayDemand + losses;
const delta = TAP - tcpComputed;
const reserveMargin = n("powergrid","PLC2","MES.ReserveMargin", delta);
const deficitActive = b("powergrid","PLC2","MES.DeficitActive");
const factoryServed = b("powergrid","PLC2","MES.FactoryServed");
const homesServed = b("powergrid","PLC2","MES.HomesServed");
const railwayServed = b("powergrid","PLC2","MES.RailwayServed");
const heartbeat = n("misc","none","MES.Health.Heartbeat");
const watchdog = n("misc","none","MES.Health.Watchdog");
const dataStale = b("misc","none","MES.Health.DataStale");
const lastEpoch = n("misc","none","MES.Health.LastUpdateEpoch");
const ageSec = lastEpoch ? Math.max(0, Math.floor(Date.now()/1000 - lastEpoch)) : null;

function out(name, payload, extra={}) {
    msg.headers = {"Content-Type":"application/json"};
    msg.payload = {
        kpi: name,
        generatedAt: new Date().toISOString(),
        sourceUpdatedAt: s.updatedAt,
        pointCount: s.count || 0,
        ...payload,
        meta: {
            tcpPolicy: "computed_in_node_red",
            tcpFormula: "FactoryDemand + HomesDemand + RailwayDemand + Losses",
            ...extra
        }
    };
    return msg;
}

